import React, { useEffect, useRef, useState } from 'react';
import Quagga from 'quagga';

function BarcodeScanner({ onScan, onError }) {
  const scannerRef = useRef(null);
  const [isScanning, setIsScanning] = useState(false);
  const scanLock = useRef(false); // 🔐 prevents duplicate scans

  useEffect(() => {
    if (!isScanning) return;

    Quagga.init(
      {
        inputStream: {
          type: 'LiveStream',
          target: scannerRef.current,
          constraints: {
            facingMode: 'environment',
            width: { ideal: 640 },   // ✅ LOW RESOLUTION
            height: { ideal: 480 }
          }
        },
        locator: {
          patchSize: 'medium',
          halfSample: true
        },
        decoder: {
          readers: ['code_128_reader', 'ean_reader', 'ean_8_reader']
        },
        locate: true,
        numOfWorkers: navigator.hardwareConcurrency || 2,
        frequency: 5 // ✅ SLOWER SCAN RATE
      },
      (err) => {
        if (err) {
          console.error(err);
          onError?.('Camera initialization failed');
          return;
        }
        Quagga.start();
      }
    );

    Quagga.onDetected((data) => {
      if (scanLock.current) return;

      scanLock.current = true; // 🔒 lock scanning
      const code = data.codeResult.code;

      if (code) {
        onScan(code);
        setTimeout(() => {
          scanLock.current = false;
        }, 2000); // allow next scan after 2 sec
      }
    });

    return () => {
      Quagga.stop();
      Quagga.offDetected();
    };
  }, [isScanning, onScan, onError]);

  return (
    <div className="scanner-container">
      <button
        className="scan-btn"
        onClick={() => setIsScanning((s) => !s)}
      >
        {isScanning ? 'Stop Scanner' : 'Start Scanner'}
      </button>

      {isScanning && (
        <div
          ref={scannerRef}
          style={{
            width: '100%',
            height: '260px',
            borderRadius: '12px',
            overflow: 'hidden',
            marginTop: '10px'
          }}
        />
      )}
    </div>
  );
}

export default BarcodeScanner;
